-- ============ ROLES ============

-- ============ ROLE PERMISSIONS ============
-- Owner: ALL permissions
SELECT 'e2000000-0000-0000-0000-000000000001', id FROM permissions;

-- Manager: all except settings
SELECT 'e2000000-0000-0000-0000-000000000002', id FROM permissions WHERE code NOT IN ('settings.manage');

-- Cashier: sell + view
SELECT 'e2000000-0000-0000-0000-000000000003', id FROM permissions WHERE code IN (
    'product.read', 'order.create', 'order.read', 'order.update',
    'customer.create', 'customer.read', 'customer.update', 'inventory.read'
);

-- Staff: view only + create orders
SELECT 'e2000000-0000-0000-0000-000000000004', id FROM permissions WHERE code IN (
    'product.read', 'order.create', 'order.read', 'customer.read', 'inventory.read'
);

